mapper.select:
select count(*) from ( SELECT A.* FROM ( SELECT S.STOCK_ID AS stockId, S.STOCK_ITEM AS stockItem, S.STOCK_PREV_QTY AS stockPrevQty, S.STOCK_AVAIL_QTY AS stockAvailQty, S.STOCK_RESERVE_QTY AS stockReserveQty,
I.ITEM_NAME AS itemName, I.ITEM_TYPE AS itemType, I.ITEM_SAFETY_STOCK AS itemSafetyStock,
CASE WHEN S.STOCK_AVAIL_QTY <= I.ITEM_SAFETY_STOCK THEN '부족' WHEN S.STOCK_AVAIL_QTY <= I.ITEM_SAFETY_STOCK * 1.2 THEN '위험' ELSE '안전' END AS stockStatus
FROM STOCK S JOIN ITEM I ON S.STOCK_ITEM = I.ITEM_ID ) A
AND A.itemType = #{itemType}
AND A.stockStatus IN
#{status}
AND ( UPPER(A.stockId) LIKE UPPER('%' || #{searchKeyword} || '%') OR UPPER(A.stockItem) LIKE UPPER('%' || #{searchKeyword} || '%') OR UPPER(A.itemName) LIKE UPPER('%' || #{searchKeyword} || '%') )
)

select * from ( select rownum rn, I.* from ( SELECT * FROM ( SELECT A.* FROM ( SELECT S.STOCK_ID AS stockId, S.STOCK_ITEM AS stockItem, S.STOCK_PREV_QTY AS stockPrevQty, S.STOCK_AVAIL_QTY AS stockAvailQty, S.STOCK_RESERVE_QTY AS stockReserveQty,
I.ITEM_NAME AS itemName, I.ITEM_TYPE AS itemType, I.ITEM_SAFETY_STOCK AS itemSafetyStock,
CASE WHEN S.STOCK_AVAIL_QTY <= I.ITEM_SAFETY_STOCK THEN '부족' WHEN S.STOCK_AVAIL_QTY <= I.ITEM_SAFETY_STOCK * 1.2 THEN '위험' ELSE '안전' END AS stockStatus
FROM STOCK S JOIN ITEM I ON S.STOCK_ITEM = I.ITEM_ID ) A
AND A.itemType = #{itemType}
AND A.stockStatus IN
#{status}
AND ( UPPER(A.stockId) LIKE UPPER('%' || #{searchKeyword} || '%') OR UPPER(A.stockItem) LIKE UPPER('%' || #{searchKeyword} || '%') OR UPPER(A.itemName) LIKE UPPER('%' || #{searchKeyword} || '%') )
) ORDER BY stockId DESC ) I ) where rn between #{page.startRow} and #{page.endRow}

SELECT IO_ID AS ioId, IO_TYPE AS ioType, IO_REASON AS ioReason, IO_LOT AS ioLot, IO_QTY AS ioQty, IO_DATE AS ioDate FROM IO WHERE IO_LOT IN (
SELECT LOT_ID FROM LOT WHERE LOT_ITEM = (
SELECT STOCK_ITEM FROM STOCK WHERE STOCK_ID = #{stockId}
)
) ORDER BY IO_DATE DESC
